import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecutionExample {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a website to ping: ");
            String userInput = reader.readLine();

            // Construct the command using ProcessBuilder to prevent command injection
            ProcessBuilder processBuilder = new ProcessBuilder("ping", "-c", "3", userInput);

            // Start the process and read output
            Process process = processBuilder.start();
            BufferedReader processOutputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;
            while ((line = processOutputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

